        packet = self._transport._make_cmd_packet(0x1261, payload)
        resp = self._transport._wr(packet, 0x1261, timeout_s=5.0)
        if resp is None:
            return None
        parts = resp.split(b'\x00', 1)
        if len(parts) == 2:
            return SignalBoardGET_PARAMSResponse(param_name=parts[0].decode('utf-8'), value=parts[1])
