class MotorBoardCmd:
    """Command IDs for MotorBoard."""
    HEAD = 0x11
    RESET = 0x1100  # MCU software reset
    LOGIN = 0x1101  # Handshake login with timestamp
    VERSION = 0x1102  # Get firmware version
    HW_RESET = 0x1103  # Hardware reset self-check
    STATUS = 0x1104  # Query motor board status
    CHIP_CABIN_CTRL = 0x1120  # Control chip tray position
    CHIP_CABIN_READ = 0x1121  # Read chip tray position
    MAG_CTRL = 0x1122  # Control magnet position
    MAG_READ = 0x1123  # Read magnet position
    PUSHPAD_CTRL = 0x1124  # Control pogo pin plates
    PUSHPAD_READ = 0x1125  # Read pogo plate position
    FLUORESCENCE_CTRL = 0x1126  # Set fluorescence filter position
    FLUORESCENCE_READ = 0x1127  # Read fluorescence filter position
    PMT_CTRL = 0x1128  # Move PMT to position
    PMT_READ = 0x1129  # Query PMT position
    POWER_CTRL = 0x112A  # Motor board power control
    FAN_CTRL = 0x112B  # Motor board fan control
    CABIN_MAG_RESET = 0x1130  # Home chip tray and magnet axes
    PMT_RESET = 0x1131  # Home PMT motor
    FLU_RESET = 0x1132  # Home fluorescence filter
    PUSHPAD_RESET = 0x1133  # Home pogo pin plates
    PMT_MT_CTRL = 0x1140  # PMT motor control (routed from signal board)
    PMT_MT_SPEED_SET = 0x1141  # Set PMT motor speed
    MOTOR_CONTROL = 0x11B0  # Motor control — move, stop, home
    MOTOR_SPEED_SET = 0x11B1  # Set motor speed
    MOTOR_POSITION_QUERY = 0x11B3  # Query motor position
    MOTOR_OPTO_QUERY = 0x11B4  # Query all motor opto-coupler sensors
    SET_PARAMS = 0x1160  # Write parameter
    GET_PARAMS = 0x1161  # Read parameter
    PRESET_PARAMS = 0x1162  # Save all parameters to flash
    SET_ALARM_LEVEL = 0x1173  # Set alarm reporting level
    REPORT_ALARM = 0x1172  # Alarm report (device → host)
    CLEAR_ALARM = 0x1174  # Clear/confirm alarm by code
    SET_LOG_LEVEL = 0x1171  # Set log reporting level
    REPORT_LOG = 0x1170  # Log report (device → host)
    FW_PREPARE = 0x1180  # Firmware upgrade handshake
    FW_TRANSFER = 0x1181  # Firmware data transfer
    FW_RESULT = 0x1282  # Firmware upgrade result

    MOTOR_ACTION_ABSOLUTE = 0
    MOTOR_ACTION_RELATIVE = 1
    MOTOR_ACTION_STOP = 3
    MOTOR_ACTION_HOME = 4

    PARAMS = {
        "filter_defaults": "_dp_flu",
        "tray_defaults": "_dp_chip",
        "magnet_defaults": "_dp_magnet",
        "pmt_defaults": "_dp_pmt",
        "pogo_defaults": "_dp_pushpad",
        "product_model": "_dp_model",
        "tray_motor": "_mt_cabin_dp",
        "pmt_motor": "_mt_y_dp",
        "magnet_motor": "_mt_z_dp",
        "filter_motor": "_mt_flu_dp",
        "pogo_motor_left": "_mt_padl_dp",
        "pogo_motor_right": "_mt_padr_dp",
    }


class MotorBoardAlarms:
    """Alarm codes for MotorBoard."""
    CHIP_CABIN_MOTOR_FAULT = "04001"  # Chip tray motor fault
    PMT_MOTOR_FAULT = "04013"  # PMT motor fault
    MAG_Z_MOTOR_FAULT = "04025"  # Magnet Z motor fault
    FLU_MOTOR_FAULT = "04037"  # Fluorescence filter motor fault
    PUSHPAD_R_MOTOR_FAULT = "04049"  # Right pogo plate motor fault
    PUSHPAD_L_MOTOR_FAULT = "04061"  # Left pogo plate motor fault
    MAG_NOT_DISENGAGED = "04073"  # Magnet not in disengaged position
    CABIN_UNKNOWN_POS = "04074"  # Chip tray position unknown
    MAG_UNKNOWN_POS = "04075"  # Magnet position unknown
    PUSHPAD_FAULT = "04077"  # Pogo plate mechanism fault

    @staticmethod
    def to_str(code: str) -> str:
        _map = {
            "04001": "Chip tray motor fault",
            "04013": "PMT motor fault",
            "04025": "Magnet Z motor fault",
            "04037": "Fluorescence filter motor fault",
            "04049": "Right pogo plate motor fault",
            "04061": "Left pogo plate motor fault",
            "04073": "Magnet not in disengaged position",
            "04074": "Chip tray position unknown",
            "04075": "Magnet position unknown",
            "04077": "Pogo plate mechanism fault",
        }
        return _map.get(code, f"Unknown alarm: {code}")


