        if len(resp) < 7:
            return None
        raw = struct.unpack('>BBBBBBB', resp[:7])
        return MotorBoardSTATUSResponse(rst=raw[0], cabin=raw[1], mag=raw[2], flu=raw[3], lpush=raw[4], rpush=raw[5], pmt=raw[6])

