    def set_params(self, param_name: str, value: bytes) -> bool:
        """Write parameter"""
        payload = param_name.encode('utf-8') + b'\x00'
        payload += value
        packet = self._transport._make_cmd_packet(0x1160, payload)
        return self._transport._wr(packet, 0x1160, timeout_s=3.0) is not None

    def get_params(self, param_name: str) -> MotorBoardGET_PARAMSResponse | None:
        """Read parameter"""
        payload = param_name.encode('utf-8') + b'\x00'
        packet = self._transport._make_cmd_packet(0x1161, payload)
        resp = self._transport._wr(packet, 0x1161, timeout_s=5.0)
        if resp is None:
            return None
        parts = resp.split(b'\x00', 1)
        if len(parts) == 2:
            return MotorBoardGET_PARAMSResponse(param_name=parts[0].decode('utf-8'), value=parts[1])
        return None

    def preset_params(self) -> bool:
        """Save all parameters to flash"""
        payload = b''
        packet = self._transport._make_cmd_packet(0x1162, payload)
        return self._transport._wr(packet, 0x1162, timeout_s=5.0) is not None

    def set_alarm_level(self, level: int) -> bool:
        """Set alarm reporting level"""
        payload = struct.pack('>B', level)
        packet = self._transport._make_cmd_packet(0x1173, payload)
        return self._transport._wr(packet, 0x1173, timeout_s=2.0) is not None

    def clear_alarm(self, alarm_code: bytes) -> bool:
        """Clear/confirm alarm by code"""
        payload = struct.pack('>5s', alarm_code)
        packet = self._transport._make_cmd_packet(0x1174, payload)
        return self._transport._wr(packet, 0x1174, timeout_s=2.0) is not None

